import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { LIPCO_INFO } from "../constants";

export class GeminiService {
  private ai: GoogleGenAI;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  }

  async getAssistantResponse(userMessage: string, chatHistory: { role: 'user' | 'model', text: string }[]): Promise<string> {
    try {
      const systemInstruction = `
        You are the official AI Assistant for Lipco.
        About Lipco: ${LIPCO_INFO.description}
        Tagline: ${LIPCO_INFO.tagline}
        Contact: ${LIPCO_INFO.email}

        Guidelines:
        1. Be professional, innovative, and helpful.
        2. Keep responses concise and focused on how Lipco can help.
        3. If asked about services, reference Digital Transformation, AI Integration, UX Design, and Data Analytics.
        4. Use a modern, technical but accessible tone.
      `;

      const contents = chatHistory.map(msg => ({
        role: msg.role === 'user' ? 'user' : 'model',
        parts: [{ text: msg.text }]
      }));

      // Append latest message
      contents.push({
        role: 'user',
        parts: [{ text: userMessage }]
      });

      const response = await this.ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents,
        config: {
          systemInstruction,
          temperature: 0.7,
          topP: 0.8,
          maxOutputTokens: 500,
        },
      });

      return response.text || "I'm sorry, I couldn't process that. How else can I assist you with Lipco's services?";
    } catch (error) {
      console.error("Gemini API Error:", error);
      return "Connectivity issue. Please try again or contact our support team at " + LIPCO_INFO.email;
    }
  }
}

export const geminiService = new GeminiService();

